import React from 'react';

interface WebPImageProps {
    src: string;          // Путь к изображению (например: "/images/projects/example.jpg")
    alt: string;
    className?: string;
    style?: React.CSSProperties;
    onClick?: () => void;
    onError?: (e: React.SyntheticEvent<HTMLImageElement, Event>) => void;
}

const WebPImage: React.FC<WebPImageProps> = ({
    src,
    alt,
    className,
    style,
    onClick,
    onError
}) => {
    // Функция для преобразования пути в API URL
    const getApiUrl = (imagePath: string, isWebP = false) => {
        // Убираем "/images/projects/" из начала пути
        const filename = imagePath.replace(/^\/images\/projects\//, '');

        if (isWebP) {
            // Для WebP изображений используем специальный endpoint
            const webpFilename = filename.replace(/\.(jpg|jpeg|png)$/i, '.webp');
            return `http://localhost:8080/api/images/projects/webp/${webpFilename}`;
        } else {
            // Для обычных изображений
            return `http://localhost:8080/api/images/projects/${filename}`;
        }
    };

    // Генерируем WebP и fallback URLs
    const webpUrl = getApiUrl(src, true);
    const fallbackUrl = getApiUrl(src, false);

    // Если путь не начинается с "/images/projects/", используем исходный путь
    const isProjectImage = src.startsWith('/images/projects/');

    if (!isProjectImage) {
        // Для остальных изображений используем прямой путь
        return (
            <img
                src={src}
                alt={alt}
                className={className || "w-full h-full object-contain"}
                style={style}
                onClick={onClick}
                onError={onError}
            />
        );
    }

    return (
        <picture onClick={onClick} className={className} style={style}>
            {/* Браузер попытается загрузить WebP через API сначала */}
            <source srcSet={webpUrl} type="image/webp" />

            {/* Fallback для браузеров без поддержки WebP или если WebP не найден */}
            <img
                src={fallbackUrl}
                alt={alt}
                className="w-full h-full object-contain"
                onError={onError}
            />
        </picture>
    );
};

export default WebPImage;
